safe_example:
from flask import request
import ast
import json

def calculate():
    expr = request.form.get("expr")
    try:
        # SAFE: ast.literal_eval only parses Python literals
        result = ast.literal_eval(expr)
        return str(result)
    except (ValueError, SyntaxError):
        return "Invalid expression", 400
